import{_ as t,o as e,c as r,a2 as s}from"./chunks/framework.Bjylvv1V.js";const u=JSON.parse('{"title":"장기수선충당금 관리","description":"","frontmatter":{},"headers":[],"relativePath":"guide/scenarios/reserve-fund.md","filePath":"guide/scenarios/reserve-fund.md","lastUpdated":null}'),o={name:"guide/scenarios/reserve-fund.md"};function l(i,a,n,d,h,c){return e(),r("div",null,[...a[0]||(a[0]=[s(`<h1 id="장기수선충당금-관리" tabindex="-1">장기수선충당금 관리 <a class="header-anchor" href="#장기수선충당금-관리" aria-label="Permalink to &quot;장기수선충당금 관리&quot;">​</a></h1><blockquote><p><strong>소요 시간</strong>: 월별 확인 약 10분 / 전출 정산 건당 약 15분 | <strong>난이도</strong>: ★★☆ | <strong>주기</strong>: 매월 + 전출 시 수시</p></blockquote><p>장기수선충당금의 적립 현황을 관리하고, 세대 전출 시 충당금을 정산·환급하는 프로세스입니다.</p><div class="info custom-block"><p class="custom-block-title">장기수선계획 수립·공사 집행은 관리소장 업무입니다</p><p>장기수선계획의 수립·검토와 수선 공사 집행은 관리소장이 처리합니다. → <a href="/guide/scenarios/long-term-repair.html">장기수선계획 관리</a></p></div><h2 id="전체-흐름" tabindex="-1">전체 흐름 <a class="header-anchor" href="#전체-흐름" aria-label="Permalink to &quot;전체 흐름&quot;">​</a></h2><h3 id="충당금-관리-매월" tabindex="-1">충당금 관리 (매월) <a class="header-anchor" href="#충당금-관리-매월" aria-label="Permalink to &quot;충당금 관리 (매월)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 충당금 적립 현황 조회  (5분)  → 월별 적립액 확인</span></span>
<span class="line"><span>2. 관리비 부과 항목 반영  (연계) → 부과처리 시 세대별 자동 적립</span></span>
<span class="line"><span>3. 충당금 계좌 잔액 확인  (5분)  → 별도 계좌 관리 현황 점검</span></span></code></pre></div><h3 id="전출-시-충당금-정산-수시" tabindex="-1">전출 시 충당금 정산 (수시) <a class="header-anchor" href="#전출-시-충당금-정산-수시" aria-label="Permalink to &quot;전출 시 충당금 정산 (수시)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 입주 기간 확인         (2분)  → 입주일~전출일 산정</span></span>
<span class="line"><span>2. 충당금 정산 처리       (5분)  → OCCP2015 화면에서 자동 계산</span></span>
<span class="line"><span>3. 환급 처리              (5분)  → 환급액 지급 또는 차감</span></span>
<span class="line"><span>4. 정산 확인서 출력       (3분)  → 세대주에게 교부</span></span></code></pre></div><hr><h2 id="_1단계-충당금-적립-현황-조회" tabindex="-1">1단계: 충당금 적립 현황 조회 <a class="header-anchor" href="#_1단계-충당금-적립-현황-조회" aria-label="Permalink to &quot;1단계: 충당금 적립 현황 조회&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: <a href="/afms/">장기수선계획</a> &gt; 충당금 적립 현황</p></blockquote><p>월별 충당금 적립 내역을 조회하여 목표 적립액 대비 실적립액을 확인합니다.</p><h3 id="확인-포인트" tabindex="-1">확인 포인트 <a class="header-anchor" href="#확인-포인트" aria-label="Permalink to &quot;확인 포인트&quot;">​</a></h3><ul><li>[ ] 이번 달 적립액이 계획액과 일치하는가?</li><li>[ ] 누적 적립액이 충당금 계획과 맞는가?</li><li>[ ] 미납 세대의 충당금 누락분이 있는가?</li></ul><h3 id="충당금-부과-구조" tabindex="-1">충당금 부과 구조 <a class="header-anchor" href="#충당금-부과-구조" aria-label="Permalink to &quot;충당금 부과 구조&quot;">​</a></h3><p>충당금은 <strong>관리비 부과 시 자동으로 세대별 적립</strong>됩니다.</p><table tabindex="0"><thead><tr><th>단계</th><th>처리 내용</th></tr></thead><tbody><tr><td>부과처리</td><td><a href="/impo/">부과</a> &gt; <a href="/impo/process.html">부과처리</a>에서 장기수선충당금 항목 포함</td></tr><tr><td>적립</td><td>세대별 면적 비례로 자동 배분</td></tr><tr><td>누적 관리</td><td>충당금 계좌에 별도 적립·관리</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">충당금 계좌 분리 관리</p><p>장기수선충당금은 <strong>일반 관리비 계좌와 반드시 분리</strong>하여 별도 계좌로 관리해야 합니다. 용도 외 사용은 법적으로 금지되어 있습니다.</p></div><hr><h2 id="_2단계-전출-시-장기수선충당금-정산" tabindex="-1">2단계: 전출 시 장기수선충당금 정산 <a class="header-anchor" href="#_2단계-전출-시-장기수선충당금-정산" aria-label="Permalink to &quot;2단계: 전출 시 장기수선충당금 정산&quot;">​</a></h2><p>세대 입주자가 전출할 때 입주 기간 동안 납부한 충당금을 정산하여 환급합니다.</p><blockquote><p><strong>메뉴 경로</strong>: 입주자 &gt; <a href="/occp/move-out.html">전출처리</a> &gt; 장기수선충당금 (OCCP2015)</p></blockquote><h3 id="절차" tabindex="-1">절차 <a class="header-anchor" href="#절차" aria-label="Permalink to &quot;절차&quot;">​</a></h3><ol><li>장기수선충당금 화면 진입</li><li>정산 대상 세대(동·호수) 선택</li><li><strong>정산 기간</strong> 설정 (입주일 ~ 전출일)</li><li><strong>처리</strong> 클릭 → 시스템이 자동 계산</li><li>정산 내역 확인:</li></ol><table tabindex="0"><thead><tr><th>항목</th><th>내용</th></tr></thead><tbody><tr><td>입주 기간</td><td>입주일부터 전출일까지</td></tr><tr><td>월별 납부액</td><td>세대별 월 부과 금액</td></tr><tr><td>환급 금액</td><td>입주 기간 납부 총액</td></tr></tbody></table><ol start="6"><li><strong>저장</strong></li><li><strong>장기수선충당금 정산 확인서</strong> 출력 → 세대주에게 교부</li></ol><div class="tip custom-block"><p class="custom-block-title">정산 기준일</p><p>2022년 1월 13일 이후 전출 건은 <strong>월 단위</strong>로 정산됩니다. 일 단위 정산은 적용되지 않습니다.</p></div><h3 id="환급-방법" tabindex="-1">환급 방법 <a class="header-anchor" href="#환급-방법" aria-label="Permalink to &quot;환급 방법&quot;">​</a></h3><table tabindex="0"><thead><tr><th>구분</th><th>처리 방법</th></tr></thead><tbody><tr><td>현금 환급</td><td>별도 계좌로 이체</td></tr><tr><td>미납 관리비 차감</td><td>미납 잔액에서 충당금 차감 후 차액 환급</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">전출 처리 순서</p><p>장기수선충당금 정산은 <strong>전출 처리(OCCP2020) 이전</strong>에 완료해야 합니다. 전출 처리 전체 흐름은 <a href="/guide/scenarios/move-in-out.html">전출입 처리</a> 시나리오를 참고하세요.</p></div><hr><h2 id="자주-발생하는-문제" tabindex="-1">자주 발생하는 문제 <a class="header-anchor" href="#자주-발생하는-문제" aria-label="Permalink to &quot;자주 발생하는 문제&quot;">​</a></h2><h3 id="전출-시-충당금-정산-금액이-0원으로-나와요" tabindex="-1">전출 시 충당금 정산 금액이 0원으로 나와요 <a class="header-anchor" href="#전출-시-충당금-정산-금액이-0원으로-나와요" aria-label="Permalink to &quot;전출 시 충당금 정산 금액이 0원으로 나와요&quot;">​</a></h3><p><strong>원인</strong>: 부과 처리 시 해당 세대에 장기수선충당금이 부과되지 않은 경우 <strong>해결</strong>: <a href="/impo/basic.html">부과 기초정보</a>에서 해당 세대의 충당금 부과 항목을 확인하세요. 부과 이력이 없으면 정산 금액이 발생하지 않습니다.</p><h3 id="충당금-계좌와-일반-계좌가-섞여-있어요" tabindex="-1">충당금 계좌와 일반 계좌가 섞여 있어요 <a class="header-anchor" href="#충당금-계좌와-일반-계좌가-섞여-있어요" aria-label="Permalink to &quot;충당금 계좌와 일반 계좌가 섞여 있어요&quot;">​</a></h3><p><strong>원인</strong>: 충당금 별도 계좌 분리 없이 운영된 경우 <strong>해결</strong>: 즉시 별도 계좌로 분리하세요. 충당금 계좌는 <a href="/bank/">아파트뱅크</a>에서 별도 등록하여 관리합니다. 혼용 운영은 법적 제재 대상입니다.</p><h3 id="적립액과-부과액이-맞지-않아요" tabindex="-1">적립액과 부과액이 맞지 않아요 <a class="header-anchor" href="#적립액과-부과액이-맞지-않아요" aria-label="Permalink to &quot;적립액과 부과액이 맞지 않아요&quot;">​</a></h3><p><strong>원인</strong>: 미납 세대 발생 또는 부과 항목 설정 오류 <strong>해결</strong>: <a href="/recp/overdue.html">미납조회</a>에서 충당금 항목의 미수금을 확인하고, <a href="/impo/basic.html">부과 기초정보</a>에서 부과 항목 설정이 올바른지 점검하세요.</p><hr><h2 id="관련-메뉴" tabindex="-1">관련 메뉴 <a class="header-anchor" href="#관련-메뉴" aria-label="Permalink to &quot;관련 메뉴&quot;">​</a></h2><ul><li><a href="/afms/">장기수선계획</a> - 충당금 적립 현황 조회</li><li><a href="/occp/move-out.html">전출처리</a> - 충당금 정산 (OCCP2015)</li><li><a href="/guide/scenarios/long-term-repair.html">장기수선계획 관리</a> - 계획 수립·공사 집행 (관리소장 업무)</li><li><a href="/guide/scenarios/move-in-out.html">전출입 처리</a> - 전출 업무 전체 흐름</li><li><a href="/impo/process.html">부과처리</a> - 충당금 부과 항목 설정</li><li><a href="/impo/basic.html">부과 기초정보</a> - 부과 항목 등록</li></ul>`,42)])])}const b=t(o,[["render",l]]);export{u as __pageData,b as default};
